diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index e1f9f29ac6d9..698ff829b8dc 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7393,6 +7393,7 @@ VectorizationFactor LoopVectorizationPlanner::computeBestVF() {
   // simplifications not accounted for in the legacy cost model. If that's the
   // case, don't trigger the assertion, as the extra simplifications may cause a
   // different VF to be picked by the VPlan-based cost model.
+
   VPCostContext CostCtx(CM.TTI, *CM.TLI, Legal->getWidestInductionType(), CM);
   precomputeCosts(BestPlan, BestFactor.Width, CostCtx);
   assert((BestFactor.Width == LegacyVF.Width ||
@@ -8420,17 +8421,21 @@ VPWidenRecipe *VPRecipeBuilder::tryToWiden(Instruction *I,
   case Instruction::Sub:
   case Instruction::Xor:
   case Instruction::Freeze:
-    if (I->getOpcode() == Instruction::Mul) {
-      // Simplify operands of multiplications using SCEV. This is needed at the
-      // moment to match the behavior of the legacy cost-model.
-      // TODO: Generalize to any opcode and move to VPlan transformation.
+    // For operations that can benefit from SCEV-based constant folding,
+    // simplify operands before creating the recipe.
+    if (I->getOpcode() == Instruction::Mul ||
+        I->getOpcode() == Instruction::LShr ||
+        I->getOpcode() == Instruction::AShr ||
+        I->getOpcode() == Instruction::Shl) {
       SmallVector<VPValue *> NewOps(Operands);
       ScalarEvolution &SE = *PSE.getSE();
-      for (unsigned I = 0; I < Operands.size(); ++I) {
-        Value *V = NewOps[I]->getUnderlyingValue();
-        if (!isa<Constant>(V) && SE.isSCEVable(V->getType()))
-          if (auto *C = dyn_cast<SCEVConstant>(PSE.getSE()->getSCEV(V)))
-            NewOps[I] = Plan.getOrAddLiveIn(C->getValue());
+      for (unsigned Idx = 0; Idx < Operands.size(); ++Idx) {
+        Value *V = NewOps[Idx]->getUnderlyingValue();
+        if (!isa<Constant>(V) && SE.isSCEVable(V->getType())) {
+          if (auto *C = dyn_cast<SCEVConstant>(PSE.getSE()->getSCEV(V))) {
+            NewOps[Idx] = Plan.getOrAddLiveIn(C->getValue());
+          }
+        }
       }
       return new VPWidenRecipe(*I, make_range(NewOps.begin(), NewOps.end()));
     }

