diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index e1f9f29ac6d9..09c6df8ad1c1 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7393,9 +7393,44 @@ VectorizationFactor LoopVectorizationPlanner::computeBestVF() {
   // simplifications not accounted for in the legacy cost model. If that's the
   // case, don't trigger the assertion, as the extra simplifications may cause a
   // different VF to be picked by the VPlan-based cost model.
+static bool shouldIgnoreShiftZeroDisagreement(const VectorizationFactor &BestFactor,
+                                             const VectorizationFactor &LegacyVF,
+                                             Loop *OrigLoop) {
+  // Check if the loop contains shift operations with constant zero operands
+  // which might be handled differently by the two cost models.
+  for (BasicBlock *BB : OrigLoop->blocks()) {
+    for (Instruction &I : *BB) {
+      if (auto *SI = dyn_cast<BinaryOperator>(&I)) {
+        if (SI->getOpcode() == Instruction::LShr ||
+            SI->getOpcode() == Instruction::AShr ||
+            SI->getOpcode() == Instruction::Shl) {
+          // Check if the shift amount is a constant zero or can be determined as zero
+          if (auto *CI = dyn_cast<ConstantInt>(SI->getOperand(1))) {
+            if (CI->isZero()) {
+              return true;
+            }
+          }
+          // Check if the shift amount is a known zero via other means
+          // For example, sext/zext of zero
+          if (auto *CE = dyn_cast<ConstantExpr>(SI->getOperand(1))) {
+            if (CE->getOpcode() == Instruction::SExt || CE->getOpcode() == Instruction::ZExt) {
+              if (auto *SrcCI = dyn_cast<ConstantInt>(CE->getOperand(0))) {
+                if (SrcCI->isZero()) {
+                  return true;
+                }
+              }
+            }
+          }
+        }
+      }
+    }
+  }
+  return false;
+}
+
   VPCostContext CostCtx(CM.TTI, *CM.TLI, Legal->getWidestInductionType(), CM);
   precomputeCosts(BestPlan, BestFactor.Width, CostCtx);
-  assert((BestFactor.Width == LegacyVF.Width ||
+  assert((BestFactor.Width == LegacyVF.Width || shouldIgnoreShiftZeroDisagreement(BestFactor, LegacyVF, OrigLoop) ||
           planContainsAdditionalSimplifications(getPlanFor(BestFactor.Width),
                                                 CostCtx, OrigLoop)) &&
          " VPlan cost model and legacy cost model disagreed");
